if (pathHits.Count == 0)
        {
            _logger.LogDebug("Discovery: no 'aspire' binary found on $PATH.");
        }
        else
        {
            foreach (var pathHit in pathHits)
            {
                _logger.LogDebug(
                    "Discovery: $PATH match: '{Path}' (canonical: '{Canonical}').",
                    pathHit.OriginalPath, pathHit.CanonicalPath);
            }
        }

if (!TryReadSourceFieldFromExistingSidecar(sidecarPath, out var rawSource, out var error))
        {
            if (error is JsonException)
            {
                _logger?.LogDebug(error, "Install sidecar file '{SidecarPath}' contains malformed JSON.", sidecarPath);
            }
            else
            {
                _logger?.LogDebug(error, "Install sidecar file '{SidecarPath}' could not be read due to a path, permission, or IO error.", sidecarPath);
            }

            return new InstallSidecarReadResult.Invalid(sidecarPath, error?.Message ?? "Install sidecar file could not be read.");
        }

try
        {
            File.Delete(tempPath);
        }
        catch (IOException ex)
        {
            _logger.LogDebug(ex, "Winget first-run probe could not delete temp sidecar at {Path}.", tempPath);
        }
        catch (UnauthorizedAccessException ex)
        {
            _logger.LogDebug(ex, "Winget first-run probe could not delete temp sidecar at {Path}.", tempPath);
        }

foreach (var manifestFile in manifestFiles.OrderBy(f => f.RelativePath, StringComparer.Ordinal))
        {
            var relativePath = NormalizeRelativePath(manifestFile.RelativePath!);
            if (!skill.ShouldInstallFile(relativePath) || !ShouldInstallFile(manifestSkill, relativePath))
            {
                continue;
            }

            var fullPath = Path.Combine(_bundleDirectory.FullName, SkillsDirectoryName, skill.Name, relativePath);
            files.Add(new SkillAssetFile(relativePath, await File.ReadAllTextAsync(fullPath, cancellationToken).ConfigureAwait(false)));
        }

foreach (var line in frontmatter.Split('\n'))
        {
            if (!line.StartsWith(keyPrefix, StringComparison.Ordinal))
            {
                continue;
            }

            var value = line[keyPrefix.Length..].Trim();
            return value.Length >= 2 &&
                   ((value[0] == '"' && value[^1] == '"') || (value[0] == '\'' && value[^1] == '\''))
                ? value[1..^1]
                : value;
        }

if (!IsVersionInRange(currentCliVersion, supports.AspireCli))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.InvariantCulture,
                "Aspire skills bundle supports Aspire CLI versions '{0}', but the current CLI version is '{1}'.",
                supports.AspireCli,
                currentCliVersion));
        }

if (!string.IsNullOrWhiteSpace(supports.AspireSdk) &&
            !IsVersionInRange(currentSdkVersion, supports.AspireSdk))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.InvariantCulture,
                "Aspire skills bundle supports Aspire SDK versions '{0}', but the current SDK version is '{1}'.",
                supports.AspireSdk,
                currentSdkVersion));
        }

foreach (var op in new[] { ">=", "<=", "==", ">", "<", "=" })
        {
            if (comparator.StartsWith(op, StringComparison.Ordinal))
            {
                var operand = comparator[op.Length..];
                if (string.IsNullOrWhiteSpace(operand))
                {
                    throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle contains an invalid version comparator '{0}'.", comparator));
                }

                return (op, operand);
            }
        }

try
        {
            File.WriteAllText(Path.Combine(directory, ".lastused"), DateTimeOffset.UtcNow.ToUnixTimeSeconds().ToString(CultureInfo.InvariantCulture));
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            logger.LogDebug(ex, "Failed to update Aspire skills cache last-used marker for {Directory}.", directory);
        }

foreach (var sourceFile in Directory.GetFiles(sourceDirectory, "*", SearchOption.AllDirectories))
        {
            var relativePath = Path.GetRelativePath(sourceDirectory, sourceFile);
            var targetFile = Path.Combine(targetDirectory, relativePath);
            var targetFileDirectory = Path.GetDirectoryName(targetFile);
            if (!string.IsNullOrEmpty(targetFileDirectory))
            {
                Directory.CreateDirectory(targetFileDirectory);
            }

            File.Copy(sourceFile, targetFile, overwrite: true);
        }

try
        {
            if (Directory.Exists(directory))
            {
                Directory.Delete(directory, recursive: true);
            }
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            logger.LogDebug(ex, "Failed to delete Aspire skills cache directory {Directory}.", directory);
        }

foreach (var attestation in attestations)
        {
            var bundleNode = attestation?["bundle"];
            if (bundleNode is null)
            {
                continue;
            }

            if (bundleNode is JsonValue bundleValue && bundleValue.TryGetValue<string>(out var bundleString))
            {
                return bundleString;
            }

            return bundleNode.ToJsonString();
        }

if (!HasAspireServerConfigured(homeDirectory))
        {
            // Copilot CLI is installed and aspire is not configured - offer to configure
            _logger.LogDebug("Adding Copilot CLI applicator for global MCP configuration");
            context.AddApplicator(CreateApplicator(homeDirectory));
        }
        else
        {
            _logger.LogDebug("Aspire MCP server is already configured in Copilot CLI");
        }

while (parent is not null
            && ++depth <= maxDepth
            && !string.Equals(parent, stopDir, StringComparison.OrdinalIgnoreCase)
            && Directory.Exists(parent)
            && Directory.GetFileSystemEntries(parent).Length == 0)
        {
            Directory.Delete(parent);
            logger?.LogDebug("Removed empty directory: {Dir}", parent);
            parent = Path.GetDirectoryName(parent);
        }

foreach (var sourceFile in Directory.GetFiles(sourceDir, "*", SearchOption.AllDirectories))
        {
            var relativePath = Path.GetRelativePath(sourceDir, sourceFile);
            var targetFile = Path.Combine(targetDir, relativePath);

            var targetFileDir = Path.GetDirectoryName(targetFile);
            if (!string.IsNullOrEmpty(targetFileDir))
            {
                Directory.CreateDirectory(targetFileDir);
            }

            File.Copy(sourceFile, targetFile, overwrite: true);
        }

try
        {
            var playwrightDir = Path.Combine(workingDirectory, ".playwright");
            if (Directory.Exists(playwrightDir) && Directory.GetFileSystemEntries(playwrightDir).Length == 0)
            {
                Directory.Delete(playwrightDir);
                logger.LogDebug("Removed empty .playwright directory from {WorkingDirectory}", workingDirectory);
            }
        }
        catch (IOException ex)
        {
            logger.LogDebug(ex, "Failed to clean up .playwright directory in {WorkingDirectory}", workingDirectory);
        }

if (!SupportsV2)
        {
            // Fall back to v1
            var filter = request?.Filter;
            await foreach (var snapshot in WatchResourceSnapshotsAsync(includeHidden: true, cancellationToken).ConfigureAwait(false))
            {
                if (!string.IsNullOrEmpty(filter) && !snapshot.Name.Contains(filter, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }
                yield return snapshot;
            }
            yield break;
        }

try
        {
            await rpc.InvokeWithProfilingAsync<StopAppHostResponse>(
                _profilingTelemetry,
                "auxiliary",
                "StopAsync",
                [request ?? new StopAppHostRequest()],
                cancellationToken).ConfigureAwait(false);
            return true;
        }
        catch (RemoteMethodNotFoundException)
        {
            // Fall back to v1
            return await StopAppHostAsync(cancellationToken).ConfigureAwait(false);
        }

while (!cancellationToken.IsCancellationRequested && DateTime.UtcNow - startTime < maxWait)
        {
            var rpcTask = GetRpcTaskAsync();
            if (rpcTask.IsCompletedSuccessfully)
            {
                logger.LogDebug("Reconnection completed successfully");
                return;
            }

            await Task.Delay(500, cancellationToken).ConfigureAwait(false);
        }

try
            {
                await ReconnectInternalAsync().ConfigureAwait(false);
            }
            catch (Exception ex)
            {
                logger.LogWarning(ex, "Failed to reconnect backchannel");
            }
            finally
            {
                lock (_lock)
                {
                    _isReconnecting = false;
                }
            }

if (inScopeConnections.Count > 1)
        {
            var paths = inScopeConnections
                .Where(c => c.AppHostInfo?.AppHostPath != null)
                .Select(c => c.AppHostInfo!.AppHostPath)
                .ToList();

            var pathsList = string.Join("\n", paths.Select(p => $"  - {p}"));

            throw new McpProtocolException(
                $"Multiple Aspire AppHosts are running in the scope of the MCP server's working directory. " +
                $"Use the 'select_apphost' tool to specify which AppHost to use.\n\nRunning AppHosts:\n{pathsList}",
                McpErrorCode.InternalError);
        }

if (!string.IsNullOrEmpty(SelectedAppHostPath))
            {
                var selectedConnection = connections.FirstOrDefault(c =>
                    c.AppHostInfo?.AppHostPath != null &&
                    string.Equals(Path.GetFullPath(c.AppHostInfo.AppHostPath), Path.GetFullPath(SelectedAppHostPath), StringComparison.OrdinalIgnoreCase));

                if (selectedConnection != null)
                {
                    return selectedConnection;
                }

                // Clear the selection since the AppHost is no longer available
                SelectedAppHostPath = null;
            }

try
        {
            lease = BundleVersionLease.Acquire(activeVersion.Value.VersionDirectory, holderKind, commandName);
            return new BundleLayoutLease(
                CreateVersionRootedLayout(activeVersion.Value.VersionDirectory),
                lease);
        }
        catch
        {
            lease?.Dispose();
            throw;
        }

if (wingetFirstRunProbe is not null && OperatingSystem.IsWindows())
        {
            var realBinaryPath = CliPathHelper.ResolveSymlinkOrOriginalPath(processPath, logger);
            var binaryDir = Path.GetDirectoryName(realBinaryPath);
            if (!string.IsNullOrEmpty(binaryDir))
            {
                wingetFirstRunProbe.Run(binaryDir);
            }
        }

if (!IsVersionedLayoutValid(tempDir))
        {
            var badPath = $"{activeVersionDir}{BadSuffixPrefix}{Environment.TickCount64}";
            logger.LogError("Extracted bundle at {Path} failed verification; renaming to {BadPath}.", tempDir, badPath);
            try
            {
                Directory.Move(tempDir, badPath);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                logger.LogWarning(ex, "Unable to preserve failed bundle at {BadPath}; deleting instead.", badPath);
                FileDeleteHelper.TryDeleteDirectory(tempDir);
            }
            return false;
        }

try
        {
            Directory.Move(tempDir, activeVersionDir);
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            logger.LogError(ex, "Failed to promote {TempDir} to {ActiveDir}.", tempDir, activeVersionDir);
            FileDeleteHelper.TryDeleteDirectory(tempDir);
            return false;
        }

if (!IsVersionedLayoutValid(activeVersionDir))
        {
            var badPath = $"{activeVersionDir}{BadSuffixPrefix}{Environment.TickCount64}";
            logger.LogError("Post-rename validation failed for {Path}; renaming to {BadPath}.", activeVersionDir, badPath);
            try
            {
                Directory.Move(activeVersionDir, badPath);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                logger.LogWarning(ex, "Unable to preserve failed bundle at {BadPath}.", badPath);
            }
            return false;
        }

if (!string.IsNullOrEmpty(existingVersion))
        {
            var versionId = ComputeVersionId(existingVersion);
            var markerVersionDir = Path.Combine(extractDir, VersionsDirectoryName, versionId);
            if (IsVersionedLayoutValid(markerVersionDir))
            {
                return (versionId, markerVersionDir);
            }
        }
